  ('diplomatic-0248a032-moex-00415', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-111-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '國際法院在 2010 年公布有關科索沃獨立宣言合法性的諮詢意見。關於這份諮詢意見，下列敘述 何者正確？', '["此諮詢意見係由塞爾維亞向國際法院提出請求而作成", "國際法院認為科索沃宣布獨立之行為未違反國際法", "國際法院認為人民自決權於殖民地人民範疇外亦適用", "國際法院認為其他國家承認科索沃為獨立國家有溯及至宣布獨立之日的效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:57+00:00", "source_pdf_sha1": "e1a4d6d077aa", "answer_pdf_sha1": "daee9d1e682f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL)
